import React from 'react';

const Navbar = ({ active, setActive, onGoHome }) => {
  const menuItems = ["Início", "Serviços", "Agendamentos", "Contato"];

  return (
    <nav className="pb-navbar">
      <div className="pb-brand">
        <div className="pb-logo-wrap">
          <div className="pb-logo">
            <span className="pb-logo-text">PB</span>
          </div>
        </div>
        <div className="pb-brand-name">
          <span>Palheta</span>
          <span>Barbearia</span>
        </div>
      </div>

      <ul className="pb-nav-links">
        {/* BOTÃO HOME ADICIONADO AQUI */}
        <li>
          <button 
            onClick={onGoHome} 
            className="pb-nav-link"
            style={{ color: 'var(--amarelo)', fontWeight: 'bold' }}
          >
            ← VOLTAR
          </button>
        </li>

        {menuItems.map((item) => (
          <li key={item}>
            <button
              onClick={() => setActive(item)}
              className={`pb-nav-link ${active === item ? "active" : ""}`}
            >
              {item}
            </button>
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default Navbar;
